  1→import {
  2→  type ReactNode,
  3→  useCallback,
  4→  useEffect,
  5→  useMemo,
  6→  useRef,
  7→  useState,
  8→} from 'react';
  9→import './list.scss';
 10→import { ListContext } from './list_context';
 11→
 12→interface ListProps {
 13→  children: ReactNode;
 14→  itemCount: number;
 15→  onActiveIndexChange?: (index: number) => void;
 16→  onAction?: (index: number) => void;
 17→  showDetail?: boolean;
 18→  detail?: ReactNode;
 19→}
 20→
 21→export function List({
 22→  children,
 23→  itemCount,
 24→  onActiveIndexChange,
 25→  onAction,
 26→  showDetail,
 27→  detail,
 28→}: ListProps) {
 29→  const [activeIndex, setActiveIndexRaw] = useState(0);
 30→  const containerRef = useRef<HTMLDivElement>(null);
 31→
 32→  const setActiveIndex = useCallback(
 33→    (index: number) => {
 34→      setActiveIndexRaw(index);
 35→      onActiveIndexChange?.(index);
 36→    },
 37→    [onActiveIndexChange],
 38→  );
 39→
 40→  useEffect(() => {
 41→    if (itemCount === 0) {
 42→      setActiveIndex(0);
 43→    } else if (activeIndex >= itemCount) {
 44→      setActiveIndex(itemCount - 1);
 45→    }
 46→  }, [
 47→    itemCount,
 48→    activeIndex,
 49→    setActiveIndex,
 50→  ]);
 51→
 52→  useEffect(() => {
 53→    const container = containerRef.current;
 54→    if (!container) return;
 55→
 56→    const activeElement = container.querySelector<HTMLElement>(
 57→      `[data-list-index="${activeIndex}"]`,
 58→    );
 59→    activeElement?.scrollIntoView({ block: 'nearest' });
 60→  }, [activeIndex]);
 61→
 62→  useEffect(() => {
 63→    function handleKeyDown(e: KeyboardEvent) {
 64→      if (itemCount === 0) return;
 65→
 66→      if (e.ctrlKey && !e.metaKey && !e.altKey) {
 67→        if (e.key === 'n') {
 68→          e.preventDefault();
 69→          setActiveIndex(activeIndex < itemCount - 1 ? activeIndex + 1 : 0);
 70→          return;
 71→        }
 72→        if (e.key === 'p') {
 73→          e.preventDefault();
 74→          setActiveIndex(activeIndex > 0 ? activeIndex - 1 : itemCount - 1);
 75→          return;
 76→        }
 77→      }
 78→
 79→      if (e.metaKey || e.ctrlKey || e.altKey) return;
 80→
 81→      if (e.key === 'ArrowDown') {
 82→        e.preventDefault();
 83→        setActiveIndex(activeIndex < itemCount - 1 ? activeIndex + 1 : 0);
 84→      } else if (e.key === 'ArrowUp') {
 85→        e.preventDefault();
 86→        setActiveIndex(activeIndex > 0 ? activeIndex - 1 : itemCount - 1);
 87→      } else if (e.key === 'Enter') {
 88→        e.preventDefault();
 89→        onAction?.(activeIndex);
 90→      }
 91→    }
 92→
 93→    window.addEventListener('keydown', handleKeyDown);
 94→    return () => window.removeEventListener('keydown', handleKeyDown);
 95→  }, [
 96→    activeIndex,
 97→    itemCount,
 98→    setActiveIndex,
 99→    onAction,
100→  ]);
101→
102→  const contextValue = useMemo(
103→    () => ({
104→      activeIndex,
105→      setActiveIndex,
106→    }),
107→    [
108→      activeIndex,
109→      setActiveIndex,
110→    ],
111→  );
112→
113→  if (showDetail) {
114→    return (
115→      <ListContext value={contextValue}>
116→        <div className="list-detail-split">
117→          <div
118→            ref={containerRef}
119→            className="list list--with-detail"
120→            role="listbox"
121→            id="command-list"
122→          >
123→            {children}
124→          </div>
125→          <div className="list-detail-panel">{detail}</div>
126→        </div>
127→      </ListContext>
128→    );
129→  }
130→
131→  return (
132→    <ListContext value={contextValue}>
133→      <div ref={containerRef} className="list" role="listbox" id="command-list">
134→        {children}
135→      </div>
136→    </ListContext>
137→  );
138→}
